"""
mkt-original — Proverbs 4–6 (85 verses)
Run: python3 scripts/zc-original-proverbs-4-6.py
Ch4: Father's wisdom discourse — path of the righteous (v18); guard the heart (v23).
Ch5: Warning against the 'zarah' (strange/foreign woman); cistern/well marriage imagery (v15-19).
Ch6: Suretyship, the ant and sluggard, seven abominations (v16-19), lamp/light (v23), adultery.
Key terms: musar (discipline), zarah (strange woman), peles (level path), beliyya'al (worthlessness).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "4": {
    "1": "<p>The address shifts to the plural 'sons' (<em>bānim</em>), suggesting a wisdom teacher addressing students, though the singular 'father's instruction' (<em>mūsar 'āb</em>) maintains the family model. <em>Mūsar</em> is Proverbs' governing term for educational discipline — encompassing instruction, correction, and the character formed by it; Greek <em>paideia</em> captures it best.</p>",
    "2": "<p><em>Leqaḥ</em> (teaching/what is received) is what the student takes away; <em>tōrāh</em> here means instruction or guidance rather than the Mosaic law specifically. Both terms denote received wisdom rather than innate insight.</p>",
    "3": "<p><em>Yāḥîd</em> (only/tender) is rare in this sense; the parallel 'beloved' (<em>rāk</em>, tender) creates a picture of childhood cherishing. The father recalls being his father's treasured pupil — wisdom is transmitted person to person, not merely text to reader.</p>",
    "4": "<p><em>Yiḥzaq</em> — 'lay hold of' — is the same root used of Boaz 'catching' Ruth's hand; the grip on wisdom must be as firm as a physical hold. The negative command 'do not let your heart let go' (<em>al-yirepaḥ libbẹkā</em>) frames wisdom as something that can slip away.</p>",
    "5": "<p><em>Qenēh</em> (get/acquire) appears in both v5 and v7 — wisdom is framed as a commodity to be obtained with effort. The same verb in v7 creates wordplay: 'the beginning of wisdom: get wisdom.' This does not mean wisdom is for sale but that it requires active pursuit.</p>",
    "6": "<p>Personified wisdom (<em>ḥokmāh</em>) becomes a guardian: 'she will keep you' (<em>tiŝmerẹkā</em>). The protective-companion imagery begins here and culminates in ch8's full personification. The condition is simply 'do not forsake her' — wisdom is lost by neglect, not by attack.</p>",
    "7": "<p>'The beginning of wisdom: get wisdom' (<em>rē'šît ḥokmāh qenēh ḥokmāh</em>) is intentionally circular and emphatic: the first, most important thing you can do is pursue wisdom itself. <em>Rē'šît</em> can mean 'beginning', 'first in importance', or 'principal thing' — likely all three here.</p>",
    "8": "<p><em>Salselehā</em> (exalt her) is a hapax in the Piel, probably meaning 'lift up' or 'honor' — what you prize, you are prized by. The reciprocity of the wisdom relationship (honor wisdom → be honored by wisdom) runs through Proverbs 1–9's extended wisdom-personification.</p>",
    "9": "<p>Wisdom gives a 'garland of grace' (<em>livyat ḥēn</em>) and a 'crown of glory' (<em>keteret tipʾāret</em>) — both royal-martial imagery applied to the wise person. The MKT preserves 'garland' and 'crown' for these concrete terms rather than abstracting to 'honor.'</p>",
    "10": "<p>The father promises that receiving (<em>qabbēl</em>) his words will multiply the son's years. Long life as the reward of wisdom is a recurring Proverbs motif; Deuteronomy uses the same promise for Torah observance, grounding the wisdom tradition in covenant theology.</p>",
    "11": "<p>'I have taught you' (<em>hôrêtîkā</em>) and 'I have led you' (<em>hidractîkā</em>) use different verbs for instruction and guidance — the combination covers both theoretical teaching and practical mentoring, both knowing the way and walking it.</p>",
    "12": "<p><em>Tsārar</em> (be hampered/narrow) — 'your step will not be cramped/hampered.' The image is of unimpeded walking: wisdom gives sure footing and spacious movement. The antithesis — stumbling (<em>tikasel</em>) — describes the gait of the wicked in v19.</p>",
    "13": "<p>'Hold fast to discipline' (<em>hāzēq bammûsār</em>) — the same grip vocabulary as v4. The climactic identification: <em>hî' ḥayyêkā</em> = 'she is your life.' Wisdom is not merely instrumental to good living; she is life itself. The NT identification of Christ as the wisdom of God (1 Cor 1:24) takes up this life-identification directly.</p>",
    "14": "<p>The father turns to negative commands: 'do not enter the path of the wicked' (<em>al-tābô' bĕ'oraḥ rĕšā'îm</em>). The two-way motif — wisdom's path vs. the path of the wicked — structures all of ch4.</p>",
    "15": "<p><em>Perā'ēhû</em> — 'shun it/avoid it' — is intensive: not just 'don't go there' but 'actively turn away from it.' The fourfold imperative in v15 (shun, do not travel it, turn away, pass on) underscores the urgency of avoidance.</p>",
    "16": "<p>The portrait of the wicked is relentlessly active: they cannot sleep unless they do evil — wickedness is compulsive, not merely chosen. <em>Nigrĕlāh šēnātam</em> = 'their sleep is robbed/taken away' if they have not caused someone to stumble. This describes addiction to wrongdoing.</p>",
    "17": "<p>'They eat the bread of wickedness and drink the wine of violence' (<em>leḥem riš'āh... yêyn ḥamāsîm</em>) — the dietary metaphor describes evil as sustenance: the wicked are nourished by what destroys others. <em>Ḥāmās</em> (violence) is the word used for the wickedness that prompted the flood (Gen 6:11).</p>",
    "18": "<p><em>Nōgah</em> (brightness/gleaming) and the participle <em>hālōk wā'ōr</em> (going and shining/brightening) describe the progressive illumination of the righteous path. The comparison to 'the full day' (<em>kēdōn hayyôm</em>) — perhaps 'midday' — captures the trajectory: not a fixed light but an increasing one.</p>",
    "19": "<p>The wicked path is <em>'ăpēlâ</em> (deep darkness/gloom) — the antithesis of the brightening light of v18. <em>Bammeh yikkāšēlû lō' yāde'û</em> — 'on what they stumble they do not know' — captures the moral blindness of those who have chosen darkness: they cannot even identify their own stumbling blocks.</p>",
    "20": "<p>The father returns to the positive imperatives: <em>haqšēb</em> (incline/attend) and <em>hiṭṭēh</em> (turn/bow). Hearing wisdom requires physical posture — ears inclined, heart directed. The teaching presupposes not passive reception but active, directed attention.</p>",
    "21": "<p>'Let them not escape from your eyes' (<em>al-yāliṣûm mê'êneyḵā</em>) — keep wisdom in sight. The counterpart to the eyes not straying (v25) is wisdom staying within your field of vision. <em>Šomerem bĕtôk libbẹḵā</em> = 'guard them in the center of your heart.'</p>",
    "22": "<p><em>Ḥayyîm hēm lĕmōṣê'êhem</em> — 'life they are for those who find them' — repeating the life-identification of v13 but now applied to the specific 'words' and 'sayings' of v20. Wisdom's words have life-giving power; <em>marpe'</em> (healing/health) points to their curative as well as preserving function.</p>",
    "23": "<p>'Guard your heart above all else' (<em>mikkol-mišmār nĕṣōr libbẹkā</em>) — the most concentrated command in the father's discourse. <em>Tôṣe'ôt ḥayyîm</em> = 'the outflowings/issues of life' — the heart is the source from which all of life flows. MKT 'source from which life flows' captures both the outflow image and the causal primacy of the heart over all behavior.</p>",
    "24": "<p>'Remove from you crookedness of mouth' (<em>hāsēr mimmẹkā 'iqqeš peh</em>); <em>'iqqēš</em> (crooked/perverse) describes the twisted mouth — speech that distorts reality. The imperative to remove crooked speech flows directly from the previous verse: what flows from a guarded heart is straight speech.</p>",
    "25": "<p>'Let your eyes look directly ahead' (<em>êneyḵā lĕnōkaḥ yabiṭû</em>) — the father links right vision with right walking. <em>Nōkaḥ</em> = directly/straight before you; <em>le'umat</em> = right in front. The disciplined gaze that does not wander is the complement to the guarded heart.</p>",
    "26": "<p><em>Peles</em> (balance/level) is the root of the call to 'ponder/level' the path of your feet. The MKT 'ponder' captures both the reflective and the smoothing/leveling senses. The disciplined life is not impulsive but measured — paths are consciously assessed before being taken.</p>",
    "27": "<p>'Do not swerve right or left' (<em>al-tiṭ yāmîn ûśmō'l</em>) — the final verse of ch4 frames the entire discourse with the two-way imagery: the righteous path is straight, and departures in either direction lead away from it. <em>Hāsēr raglĕḵā mērā'</em> = 'turn your foot away from evil.'</p>"
  },
  "5": {
    "1": "<p>The singular address resumes ('my son'). <em>Ḥokmātî</em> = 'my wisdom'; <em>lĕtôratî</em> = 'to my instruction.' The opening call to listen (as in 4:1, 4:10, 4:20) frames the entire adultery-warning as a disciplinary address, not a moralistic lecture.</p>",
    "2": "<p><em>Mĕzimmôt</em> (discretion/prudent plans) and <em>da'at</em> (knowledge) are the positive qualities that the father's instruction preserves. The threat from the 'strange woman' is precisely to these: she offers apparent intimacy while destroying genuine wisdom.</p>",
    "3": "<p><em>Zārāh</em> (strange/foreign woman) from the verb <em>zûr</em> (to turn aside, be strange/foreign) — the term may denote a foreign woman, a prostitute, or simply a woman who is 'other' (someone else's wife). <em>Nōpet tiṭṭōpenāh śiptê zārāh</em> = 'honeycomb drips the lips of the strange woman.' The seductive speech is figured as the sweetest food before revealing its bitterness in v4.</p>",
    "4": "<p><em>Mar</em> (bitter) and <em>la'anāh</em> (wormwood/gall) describe the aftertaste of the strange woman's speech — poison masked as honey. <em>Pîpîyôt</em> = double-edged (sword), from the word for 'mouth.' The weapon that kills with both sides of its blade mirrors the speech that seduces and destroys.</p>",
    "5": "<p>'Her feet go down to death' (<em>raggleyā yōrĕdôt māwet</em>) — Sheol and death are the destination of the path she leads to. The downward movement (death is below) contrasts with the upward trajectory of wisdom in v6's 'path of life.' This is the literal end of the way that 'seems right' to a man (14:12).</p>",
    "6": "<p><em>Peles ḥayyîm</em> (the balance/scale of life) — she does not ponder the path of life. Her paths wander (<em>nā'û</em>) and cannot be known (<em>lô' tēdā'</em>). The same <em>peles</em> (balance/level) that the son is to apply to his path (4:26) is conspicuously absent from hers — she does not measure consequences.</p>",
    "7": "<p>The father returns to the second-person address ('sons'/'my children') for emphasis. The resumptive call 'hear me now' signals the practical application of the warning about to follow in vv8-14.</p>",
    "8": "<p>'Keep your way far from her, and do not go near the door of her house' (<em>harḥēq mê'ālêhā darkẹkā</em>) — distance, not dialogue, is the wisdom response. The father does not say 'resist her when she speaks to you' but 'stay away from her house entirely.' Avoiding the temptation is superior to resisting it.</p>",
    "9": "<p><em>Hôdeḵā</em> (your honor/splendor) and <em>šĕnôteḵā</em> (your years) are what is lost: the substance of a life given away. <em>Le'akzārî</em> = 'to the cruel one' — the identity of the 'others' who benefit from the fool's loss (the woman's husband? death personified?) is deliberately ambiguous.</p>",
    "10": "<p>'Lest strangers be sated with your strength' (<em>yiśbĕ'û zārîm kōḥẹkā</em>) — the irony is that the 'strange woman' (<em>zārāh</em>, v3) causes the man's substance to go to 'strangers' (<em>zārîm</em>, same root). The energy and wealth that should build his own household are consumed by those who have no claim on them.</p>",
    "11": "<p><em>Wĕnāhamtā bĕ'aḥarîtẹkā</em> = 'and you will groan at your end' — <em>nāham</em> is the word for an animal's growl or roar, used here for the anguish of regret. The deathbed realization of wasted life is more devastating than any external punishment.</p>",
    "12": "<p>The retrospective voice of the regret-speaker (vv12-14): <em>sānē'tî mûsār</em> = 'I hated discipline.' The failure was not ignorance of wisdom but rejection of it — the man knew better and chose otherwise. This is Proverbs' diagnosis of moral failure: not stupidity but willful rejection of correction.</p>",
    "13": "<p><em>Qôl môrāy</em> (voice of my teachers) and <em>limmûdāy</em> (those who instructed me) — the regret is specifically about not heeding the community of wisdom-teachers. The plural suggests the wisdom school context: the instruction was available and offered; it was refused.</p>",
    "14": "<p><em>Bĕme'aṭ hāyîtî bĕkol-rā'</em> = 'I was almost in all evil' — the path of folly leads to total public disgrace; <em>bĕtôk qāhāl wĕ'ēdāh</em> = 'in the midst of the assembly and congregation.' The public nature of the shame is part of the warning: adultery destroys social standing and communal belonging.</p>",
    "15": "<p>'Drink water from your own cistern' (<em>šĕtēh-māyim mibborẹkā</em>) — <em>bôr</em> (hewn cistern) and <em>be'ēr</em> (dug well/spring) are distinct: a cistern collects rainwater and requires labor to maintain; a well accesses a living underground source. The marriage is figured as both a stored resource and a living spring — the MKT's 'cistern' and 'well' preserve this distinction.</p>",
    "16": "<p>'Should your springs be scattered outward?' (<em>yāpûṣû mayanôteyḵā ḥûṣāh</em>) — the rhetorical question challenges promiscuity: should the water that belongs to your household flow to public streets (<em>palge-māyim birĕḥōbôt</em>)? The expected answer is no — the water/sexuality of marriage belongs within the covenant household.</p>",
    "17": "<p>'Let them be for you alone, and not for strangers with you' (<em>yihyû-lĕkā lĕbaddẹkā</em>) — the exclusivity of marital sexuality is grounded in ownership: the springs are yours; they are not for strangers. This is the foundation of the positive call in v18.</p>",
    "18": "<p>'Let your fountain be blessed' (<em>yĕhî-mĕqôrĕkā bārûk</em>) — <em>mĕqôr</em> (fountain/source) is the term used for the woman's body as the source of life (and see Prov 18:4). The blessing-prayer over the wife-fountain is one of Proverbs' most tender marriage images. <em>Ēšet nĕ'ûreḵā</em> = 'wife of your youth' — the lifelong covenant relationship is in view.</p>",
    "19": "<p><em>'Ayyelet 'ahābîm</em> (loving doe/gazelle) and <em>ya'alat ḥēn</em> (graceful deer/chamois) are terms of endearment with erotic resonance. <em>Daddeyā yĕrāwwûkā bĕkol-'ēt</em> = 'let her breasts satisfy you at all times' — the Hebrew is explicit and unabashed. Proverbs does not spiritualize the marriage relationship away from its physical dimension but grounds it there. MKT preserves 'breasts' rather than euphemizing.</p>",
    "20": "<p>The rhetorical question returns: 'why be intoxicated with a foreign woman' (<em>nûkrîyyāh</em>)? The word <em>šāgāh</em> (wander/be intoxicated/go astray) describes the disoriented movement of someone who has lost their bearings — used for erring morally and for literal wandering. The contrast with the wife-of-your-youth is sharp.</p>",
    "21": "<p>'For a man's ways are before the eyes of the LORD' (<em>kî neged 'ênê YHWH darkê-'îš</em>) — the surveillance theme: the key deterrent against adultery is not fear of the husband but awareness of divine observation. <em>Pōlēs kol-ma'ggālôtāw</em> = 'and he weighs/examines all his paths.' MKT 'examines every path' captures the forensic precision of divine scrutiny.</p>",
    "22": "<p>'His iniquities will ensnare the wicked' (<em>'awōnôtāw yilkĕdûhû</em>) — the sinner is caught not by external punishment but by his own sin as a trap. <em>Ḥablê ḥaṭṭā'tô</em> = 'the cords of his sin' — sin as a rope that binds. The passive-trap image (the sin catches him) and the active-cord image (the sin binds him) are combined.</p>",
    "23": "<p><em>Yāmût bĕ'ên mûsār</em> = 'he will die for lack of discipline' — the final verse brings the entire ch5 warning to its conclusion: the rejector of wisdom dies of his rejection. <em>Bĕrōb 'iwwaltô yiš'geh</em> = 'in the greatness of his folly he will go astray/wander' — <em>šāgāh</em> echoes v20's intoxication/wandering, completing the portrait of one who can no longer find his way.</p>"
  },
  "6": {
    "1": "<p><em>'Ārabhttā lĕrê'eḵā</em> = 'you have pledged surety for your neighbor' — <em>'ārab</em> (surety/pledge) is the financial-legal term for cosigning someone else's debt. The father warns not against helping a neighbor but against the specific legal exposure of pledging surety — a common path to financial ruin in the ancient world.</p>",
    "2": "<p>'Snared (<em>nôqaštā</em>) by the words of your mouth' — the trap is self-made; the words you spoke legally bind you. The same speech that creates relationship (promises, pledges) can destroy it through careless commitment.</p>",
    "3": "<p>'Do this now, my son, and deliver yourself' — the urgency is notable: when you realize you are snared, act immediately. <em>Hitra'pēś</em> = 'be earnest/importune' in seeking release — literally 'stamp yourself' or 'abase yourself.' The pride that must be swallowed to seek release is part of the wisdom lesson.</p>",
    "4": "<p>'Give no sleep to your eyes, no slumber to your eyelids' (<em>al-titten šēnāh lĕ'êneyḵā</em>) — the urgency of escaping the pledge is contrasted implicitly with the sluggard's love of sleep (vv9-10). When a real problem demands immediate action, sleep is the enemy.</p>",
    "5": "<p>'Save yourself like a gazelle from the hunter's hand' — the animal-flight imagery emphasizes urgency and self-preservation. The gazelle (<em>ṣĕbî</em>) and the bird (<em>ṣippôr</em>) are creatures that survive by swiftness of escape; the wisdom student must imitate their speed when trapped.</p>",
    "6": "<p>'Go to the ant, you sluggard' (<em>lēk-'el-nĕmālāh 'āṣēl</em>) — <em>nĕmālāh</em> (ant) appears only twice in the OT (here and 30:25). The ant is the unexpected teacher: a creature with no king or overseer that nevertheless stores food for winter. The sluggard (<em>'āṣēl</em>) is the foil throughout vv6-11.</p>",
    "7": "<p>The ant works without authority (<em>qāṣîn</em> = officer, <em>šōṭēr</em> = overseer, <em>mōšēl</em> = ruler) compelling her. The self-motivated industry of the ant is the implicit contrast with the sluggard who requires external pressure. Wisdom is self-directing; folly is reactive and passive.</p>",
    "8": "<p>'She prepares her bread in summer and gathers her food at harvest' (<em>tākîn baqqayiṣ laḥmāh</em>) — the ant's wisdom is temporal: she works in the season of abundance for the season of scarcity. The harvesting vocabulary (<em>qāṣîr</em>) links the ant to the broader wisdom theme of providential preparation.</p>",
    "9": "<p>The rhetorical questions directed at the sluggard — 'how long will you lie, O sluggard?' (<em>ad-mātay 'āṣēl tiŝkāb</em>) — are not answered; the sluggard's response in v10 is only more sleep. The question is not a real inquiry but a rebuke disguised as curiosity.</p>",
    "10": "<p>'A little sleep, a little slumber, a little folding of the hands to rest' (<em>me'aṭ šēnôt me'aṭ tenûmôt</em>) — three minimizing phrases in a row, each reducing the rest to 'a little.' The self-deception is the point: each 'just a little more' accumulates to a life of failure.</p>",
    "11": "<p>'Poverty will come upon you like a vagabond/traveler' (<em>ûbā' kemĕhallēk rē'šeḵā</em>) — the image of poverty arriving like an unexpected traveler stresses its certainty and suddenness. <em>Māgēn</em> (shield/armed man) — the MKT 'armed man' captures the aggressive, irresistible nature of the approaching want.</p>",
    "12": "<p><em>'Îš bĕliyya'al</em> = 'man of worthlessness/belial' — <em>bĕliyya'al</em> is a compound term (beli + ya'al = 'without profit/worth') describing someone of absolute moral worthlessness. <em>Hôlēk 'iqqĕšût peh</em> = 'walking with a crooked mouth' — the troublemaker's crooked speech precedes him in his path.</p>",
    "13": "<p>The troublemaker communicates deceptively through body language: winking eyes (<em>qōrēṣ bĕ'ênāw</em>), shuffling feet (<em>mōlēl bĕraglāw</em>), pointing fingers (<em>mōreh bĕ'eṣbe'ōtāw</em>). All three are non-verbal signals used to communicate malice while maintaining verbal deniability.</p>",
    "14": "<p>'Perversity is in his heart' (<em>tahpuḵôt bĕlibbô</em>) — <em>tahpuḵôt</em> (perversities/distortions) denotes a fundamental inversion of values. <em>Ḥōrēš rā'</em> = 'devising/plowing evil'; <em>yĕšallēaḥ mĕdānîm</em> = 'sending out discord/strife' — the troublemaker is an active agent of communal damage.</p>",
    "15": "<p>'Therefore his calamity will come suddenly' (<em>'al-kēn pittō'om yābô' 'êdô</em>) — the sudden destruction of the troublemaker mirrors the sudden arrival of poverty for the sluggard (v11). <em>Peta'</em> (suddenly) is emphatic; <em>wĕ'ên marpē'</em> = 'and there is no healing/remedy' — this ruin is irreversible.</p>",
    "16": "<p>The numerical saying ('six things... seven') is a wisdom genre (cf. Amos 1-2; Prov 30:15,18,21,29) in which the 'n+1' structure creates suspense and emphasizes the final item. The list that follows (vv17-19) catalogs the behaviors YHWH finds detestable (<em>tô'ēbâ</em>).</p>",
    "17": "<p>'Haughty eyes' (<em>'ênayim rāmôt</em>, lit. 'lifted eyes') head the list. The seven abominations: (1) haughty eyes, (2) lying tongue (<em>lĕšôn šāqer</em>), (3) hands that shed innocent blood (<em>yādayim šōpĕkôt dām nāqî</em>). The list moves from internal attitude (pride) to speech to action, showing the descent of wickedness from disposition to deed.</p>",
    "18": "<p>Continuing the list: (4) a heart that devises wicked plans (<em>lēb ḥōrēš maḥšĕbôt 'āwen</em>), (5) feet that run quickly to evil (<em>raglayim mĕmahărôt lārûṣ lārā'āh</em>). The heart, feet, and earlier the tongue and hands create a whole-body portrait of wickedness — no faculty is excluded from the service of evil.</p>",
    "19": "<p>Items (6) and (7): a false witness who breathes out lies (<em>mēpîaḥ kĕzābîm 'ēd šāqer</em>) and one who sows discord among brothers (<em>ûmĕšallēaḥ mĕdānîm bên 'aḥîm</em>). Item 7 — discord-sowing — is the culminating abomination, returning to the troublemaker portrait of vv12-14. Communal harmony is the supreme social good whose violation is most detested.</p>",
    "20": "<p>'Keep the commandment of your father' (<em>nĕṣōr miṣwat 'ābîḵā</em>) — the family-wisdom frame resumes. <em>Miṣwāh</em> (commandment) and <em>tôrāh</em> (instruction/teaching) placed in parallel reflect the convergence of family wisdom and covenant instruction in Proverbs: the father's teaching is functionally Torah.</p>",
    "21": "<p>'Bind them on your heart continually' (<em>qāšrēm 'al-libbẹḵā tāmîd</em>) and 'tie them around your neck' (<em>'anddēm 'al-gargrōteḵā</em>) — the physical-binding metaphor parallels the tefillin/mezuzah commands in Deut 6:8-9, suggesting that wisdom instruction has the same binding authority as covenant law. The MKT 'bind them on your heart' preserves this.  </p>",
    "22": "<p>'When you walk, it will lead you' (<em>bĕhithalleḵḵā tanhēh 'ōtāḵ</em>); 'when you lie down, it will watch over you' (<em>bĕšāḵbĕkā tiŝmōr 'ālêḵā</em>); 'when you wake, it will talk with you' (<em>wăhăqiṣōtā hî' tĕśîḥeḵā</em>) — the wisdom that is internalized (vv20-21) becomes a constant guide and companion throughout every state of daily life.</p>",
    "23": "<p>'For the command is a lamp and the teaching is a light' (<em>kî nēr miṣwāh wĕtôrāh 'ôr</em>) — <em>nēr</em> (lamp) and <em>'ôr</em> (light) are distinct: the command is a handheld lamp (immediate, portable guidance); the teaching is light itself (the broader illumination of understanding). Together they define 'the way of life' (<em>derek ḥayyîm</em>). Psalm 119:105 applies the same imagery to the word of God.</p>",
    "24": "<p>'To guard you from the evil woman' (<em>lĕšomrĕkā mê'ēšet rā'</em>) — the lamp/light of wisdom has a specific protective function: to guard against the evil woman/adulteress (<em>nēkrîyyāh</em>, foreign woman). <em>Ḥĕlaqat lāšôn nākrîyyāh</em> = 'the smooth tongue of the foreign woman' — the honeyed speech of ch5:3 returns.</p>",
    "25": "<p>'Do not desire her beauty in your heart' (<em>al-taḥmod yopyāh bĕlibbẹkā</em>) — the inner prohibition precedes the outer: desire is the first temptation. The eyelid (<em>'appappayim</em>, unique term) reference describes seductive glancing. The command parallels the 10th commandment's prohibition on covetousness, grounding the adultery warning in covenant ethics.</p>",
    "26": "<p>The economic comparison: a prostitute's price is a loaf of bread, but the adulterous wife hunts for a precious life (<em>nāpĕš yĕqārāh tāṣûd</em>). The contrast is stark: the prostitute's transaction costs money; the adultery with a married woman costs everything — the 'precious life' is the adulterer's own.</p>",
    "27": "<p>'Can a man carry fire in his bosom (<em>ḥēqô</em>) and his clothes not be burned?' — the rhetorical question makes the adultery-is-fire analogy obvious. <em>Ḥēq</em> (bosom/lap) is deliberately physical; the fire-in-the-bosom image describes an intimate destruction that cannot be contained.</p>",
    "28": "<p>'Or can one walk on hot coals and his feet not be burned?' — the second rhetorical question extends the fire imagery. The point is not that fire is powerful but that fire is fire: its destructive effect is natural and inevitable, not a matter of luck or circumstance.</p>",
    "29": "<p>'So is the man who goes in to his neighbor's wife' (<em>kēn habbā' el-'ēšet rē'ēhû</em>) — the explicit application of the two fire-rhetorical-questions. The adultery is not merely immoral but physically self-destructive; the 'none who touches her will go unpunished' (<em>lō' yinnāqeh</em>) is the same language used for YHWH 'not clearing the guilty' in Exodus 34:7.</p>",
    "30": "<p>'People do not despise a thief if he steals to satisfy his hunger' — the comparison is surprising: the thief who steals for hunger has some degree of understandable motive, even though he will still pay the penalty. This introduces a comparison to highlight how much worse adultery is.</p>",
    "31": "<p>'But if he is caught, he will pay sevenfold' (<em>yĕšallēm šib'ātayim</em>) — the sevenfold penalty exceeds Exodus 22:4's double-restitution requirement, suggesting that Proverbs is using a proverbial figure for 'complete/total restitution' rather than a specific legal quantity. The thief, though his motive is understandable, still bears full consequences.</p>",
    "32": "<p>'He who commits adultery lacks sense' (<em>nō'ēp 'iššāh ḥasar-lēb</em>) — <em>ḥasar-lēb</em> (lacking heart/mind) is Proverbs' clinical diagnosis: not wickedness primarily but stupidity. The adulterer destroys his own life (<em>mĕšaḥēt napšô hû'</em> = 'he who destroys himself does it') — the act is self-harm in the most fundamental sense.</p>",
    "33": "<p>'Wounds and dishonor he will get' (<em>nega' wĕqālôn yimṣā'</em>) — the physical violence implied (<em>nega'</em> = wound/blow) anticipates the cuckolded husband's vengeance in v34. <em>Wĕḥerpātô lō' timmāḥeh</em> = 'and his reproach will not be wiped away' — unlike theft, the shame of adultery is permanent; there is no restitution that restores reputation.</p>",
    "34": "<p>'For jealousy makes a man furious' (<em>kî qin'āh ḥĕmat-gāber</em>) — the husband's jealousy (<em>qin'āh</em>) is presented as natural and fierce: a force that cannot be reasoned with. <em>Lō' yaḥmôl bĕyôm nāqām</em> = 'he will not spare in the day of vengeance' — the day of reckoning is certain.</p>",
    "35": "<p>'He will not accept any ransom, nor be appeased though you multiply gifts' — in contrast to the thief who can make full restitution (v31), there is no financial resolution for adultery's offense against a marriage. No <em>kōper</em> (ransom/compensation) satisfies. The honor offense is categorical and irredeemable — the ultimate demonstration of why adultery, unlike theft, destroys the adulterer completely.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-original', 'proverbs', existing)
    total = sum(len(v) for v in PROVERBS.values())
    print(f'proverbs mkt-original: wrote {total} verses for ch 4–6')

if __name__ == '__main__':
    main()
